        "id": "alaska-long-term-care-ombudsman",
        "name": "Long-Term Care Ombudsman Program",
        "shortName": "Ombudsman Program",
        "tagline": "Free advocate to investigate complaints and resolve problems when your parent is mistreated in assisted living or nursing homes.",
        "programType": "resource",
        "complexity": "simple",
        "geographicScope": {
          "type": "federal",
          "stateVariation": true,
          "localEntities": [
            {
              "name": "Main office: 3745 Community Park Loop, Suite 200, Anchorage, AK 99508",
              "type": "service-area"
            },
            {
              "name": "Statewide volunteer network",
              "type": "service-area"
            }
          ]
        },
        "intro": "If your parent lives in an Alaska nursing home or assisted living facility and faces problems with care, safety, or rights violations, the Long-Term Care Ombudsman Program provides free advocacy and complaint investigation. Because trained ombudsmen are independent from facilities and government agencies, they can investigate issues objectively and work to resolve problems directly with facility staff.\n\nThe program serves any resident age 60+ in long-term care facilities statewide, regardless of income. Certified ombudsmen visit every skilled nursing facility and licensed assisted living home in Alaska at least once per year, and respond to specific complaints about health, safety, welfare, or resident rights violations.",
        "savingsRange": "",
        "savingsSource": "Free service",
        "savingsVerified": true,
        "structuredEligibility": {
          "summary": [
            "Age 60+",
            "Living in Alaska long-term care facility",
            "No income limits",
            "Complaint about facility care or rights"
          ],
          "ageRequirement": "60+",
          "incomeTable": null,
          "assetLimits": null,
          "functionalRequirement": null,
          "otherRequirements": [
            "Must be residing in an Alaska assisted living home or nursing home",
            "Must have a complaint or issue related to health, safety, welfare, or rights in the facility"
          ],
          "povertyLevelReference": null
        },
        "applicationGuide": {
          "method": "multiple",
          "summary": "Call the toll-free hotline at 800-730-6393 to report a complaint — no paperwork required to start.",
          "steps": [
            {
              "step": 1,
              "title": "Contact the ombudsman office",
              "description": "Call 907-334-4480 or toll-free 800-730-6393 (Monday-Friday 8:00 a.m. to 4:30 p.m.) or submit online complaint form at akoltco.org"
            },
            {
              "step": 2,
              "title": "Describe the problem",
              "description": "Provide facility name and description of the issue — no formal documentation required for initial contact"
            },
            {
              "step": 3,
              "title": "Ombudsman investigates",
              "description": "Certified ombudsman will investigate the complaint and work with facility staff to resolve the issue"
            }
          ],
          "processingTime": "Complaint investigations handled promptly by certified ombudsmen",
          "waitlist": null,
          "tip": "You don't need to gather documentation before calling — the ombudsman can help determine what information is needed during the investigation.",
          "urls": [
            {
              "label": "Online Complaint Form",
              "url": "https://akoltco.org"
            }
          ]
        },
        "contentSections": [
          {
            "type": "county-directory",
            "heading": "Contact Information",
            "offices": [
              {
                "name": "Alaska Long-Term Care Ombudsman",
                "type": "service-area",
                "phone": "907-334-4480 or 800-730-6393",
                "address": "3745 Community Park Loop, Suite 200, Anchorage, AK 99508"
              }
            ]
          },
          {
            "type": "callout",
            "tone": "tip",
            "text": "This program provides advocacy only — it cannot provide financial assistance, healthcare services, or housing. Contact them specifically when you have a complaint about facility care or need help understanding your parent's rights."
          }
        ],
        "faqs": [
          {
            "question": "What types of problems can the ombudsman help resolve?",
            "answer": "Issues with inadequate care, medication errors, abuse or neglect, billing problems, discharge planning, resident rights violations, and problems with facility policies that affect your parent's health, safety, or welfare."
          },
          {
            "question": "Can I file a complaint even if my parent doesn't want to?",
            "answer": "Yes, family members can contact the ombudsman about concerns. However, the ombudsman must respect your parent's wishes about how the complaint is handled and whether they consent to the investigation."
          },
          {
            "question": "Will the facility retaliate against my parent if I file a complaint?",
            "answer": "Retaliation is illegal and ombudsmen are trained to monitor for it. If retaliation occurs, contact the ombudsman immediately as this becomes an additional violation to investigate."
          },
          {
            "question": "How is this different from calling the state health department?",
            "answer": "Ombudsmen focus on resolving problems directly with facilities first, while state regulators investigate violations for potential penalties. Ombudsmen can often resolve issues faster and maintain ongoing relationships with facilities."
          },
          {
            "question": "What if there's no local ombudsman in my area of Alaska?",
            "answer": "The program uses trained volunteers statewide and can provide services remotely. Call the main number at 800-730-6393 and they will connect you with someone who can help regardless of your location."
          },
          {
            "question": "Can the ombudsman help if my parent lives at home but receives home care services?",
            "answer": "The program primarily serves facility residents, but adults over 60 with at-home living condition issues may qualify under Alaska law. Call to discuss your specific situation."
          }
        ],
