              {
                "name": "Financial",
                "items": [
                  "SSI/SSDI award letters or pay stubs",
                  "Rent or mortgage statements",
                  "Utility bills",
                  "Medicare premium statements",
                  "Medical bills and prescription receipts over $35/month",
                  "Transportation costs for medical appointments"
                ]
              }
