      {
        "id": "michigan-medicare-savings-programs-msp",
        "name": "Medicare Savings Programs (MSP) - QMB, SLMB, QI",
        "shortName": "Medicare Savings Programs",
        "tagline": "If your parent has Medicare and limited income, they may get $200–$2,400+ annually in premium and cost-sharing help.",
        "programType": "benefit",
        "complexity": "deep",
        "geographicScope": {
          "type": "federal",
          "stateVariation": true
        },
        "intro": "If your parent has Medicare and earns less than $1,585/month ($2,135 for couples), Michigan's Medicare Savings Programs can pay their Medicare premiums and potentially all their Medicare out-of-pocket costs. Three programs exist with different income limits and benefits: QMB covers all Medicare premiums and copays, SLMB covers just the Part B premium ($202.90/month in 2026), and QI covers the Part B premium plus prescription drug assistance.\n\nThese programs work alongside Medicare — your parent keeps their current Medicare coverage and doctors. Because the state pays Medicare costs directly, your parent won't see bills for covered services. The main catch: QI operates on first-come, first-served basis with limited funding, and QI recipients must reapply every year.",
        "savingsRange": "$202–$2,400+/year in 2026",
        "savingsSource": "Medicare Part B premium plus potential deductibles and copays",
        "savingsVerified": true,
        "structuredEligibility": {
          "summary": [
            "Has Medicare Part A and/or Part B",
            "Income below $1,585/month (single)",
            "Assets below $9,950 (single)",
            "Must not receive other Medicaid (QI only)"
          ],
          "ageRequirement": null,
          "incomeTable": [
            {
              "householdSize": 1,
              "monthlyLimit": 1350
            },
            {
              "householdSize": 2,
              "monthlyLimit": 1824
            }
          ],
          "assetLimits": {
            "individual": 9950,
            "couple": 14910,
            "countedAssets": [],
            "exemptAssets": [],
            "homeEquityCap": null
          },
          "functionalRequirement": null,
          "otherRequirements": [
            "Must be eligible for Medicare",
            "SLMB and QI require premium-free Medicare Part A",
            "QI requires annual reapplication",
            "QI not available if receiving other Medicaid benefits"
          ],
          "povertyLevelReference": "100%–135% FPL"
        },
        "applicationGuide": {
          "method": "phone",
          "summary": "Call Michigan's Medicaid line at 800-642-3195 — approval takes up to 45 days.",
          "steps": [
            {
              "step": 1,
              "title": "Call Michigan Medicaid",
              "description": "Call 800-642-3195 to request Medicare Savings Program application forms and get specific document requirements."
            },
            {
              "step": 2,
              "title": "Gather financial documents",
              "description": "Collect Medicare cards, Social Security award letters, bank statements, and any other income documentation from the past 3 months."
            },
            {
              "step": 3,
              "title": "Submit application",
              "description": "Return completed application with required documents to MDHHS. For QI program, apply early in the year due to limited funding."
            },
            {
              "step": 4,
              "title": "Follow up on processing",
              "description": "QMB decisions take up to 45 days. SLMB can be retroactive up to 3 months if eligible. QI coverage begins from the approval calendar year."
            }
          ],
          "processingTime": "Up to 45 days for QMB; timelines for SLMB and QI not specified",
          "waitlist": "QI program operates on first-come, first-served basis with limited annual funding",
          "tip": "Apply for QI early in the calendar year — funding runs out and there's a waitlist.",
          "urls": []
        },
        "contentSections": [
          {
            "type": "income-table",
            "heading": "Income Limits by Program Type (2026)",
            "rows": [
              {
                "program": "QMB",
                "individual": 1350,
                "couple": 1824,
                "coverage": "All Medicare premiums + copays/deductibles"
              },
              {
                "program": "SLMB",
                "individual": 1585,
                "couple": 2135,
                "coverage": "Part B premium only ($202.90/month)"
              },
              {
                "program": "QI",
                "individual": "Up to 135% FPL",
                "couple": "Up to 135% FPL",
                "coverage": "Part B premium + prescription drug help"
              }
            ],
            "footnote": "2026 limits; updated annually on April 1"
          },
          {
            "type": "documents",
            "heading": "What to Bring",
            "categories": [
              {
                "name": "Medicare Documentation",
                "items": [
                  "Medicare card (Part A and/or Part B)",
                  "Medicare Summary Notice (recent)"
                ]
              },
              {
                "name": "Financial Records",
                "items": [
                  "Social Security benefit statements",
                  "Pension or retirement income statements",
                  "Bank statements (checking and savings)",
                  "Investment account statements",
                  "Any other income documentation"
                ]
              }
            ]
          },
          {
            "type": "callout",
            "tone": "warning",
            "text": "QI program has limited funding and operates first-come, first-served. Apply early in the calendar year to avoid the waitlist."
          },
          {
            "type": "callout",
            "tone": "tip",
            "text": "If your parent receives SSI-related Medicaid, they automatically qualify for QMB — no separate application needed."
          }
        ],
        "faqs": [
          {
            "question": "Can Mom keep her current Medicare doctors if she gets MSP?",
            "answer": "Yes. MSP works with her existing Medicare coverage — same doctors, same Medicare benefits. The state just pays the bills Medicare doesn't cover."
          },
          {
            "question": "What happens if her income is just over the QMB limit but under SLMB?",
            "answer": "She can still qualify for SLMB, which pays her Medicare Part B premium ($202.90/month in 2026). She just won't get help with deductibles and copays like QMB provides."
          },
          {
            "question": "Does her house count toward the $9,950 asset limit?",
            "answer": "The research doesn't specify which assets are exempt, but typically the home where your parent lives doesn't count. Call 800-642-3195 to confirm what assets count in Michigan."
          },
          {
            "question": "If she qualifies, when does the coverage start?",
            "answer": "QMB starts the month after approval with no retroactive coverage. SLMB can go back up to 3 months if she was eligible. QI starts from January of the approval year (or approval month if after January)."
          },
          {
            "question": "What if she doesn't have premium-free Medicare Part A?",
            "answer": "She can still get QMB, which will pay her Part A premiums. But SLMB and QI require premium-free Part A — if she's paying for Part A, those programs aren't available."
          },
          {
            "question": "How often does she need to reapply?",
            "answer": "QMB and SLMB don't require annual reapplication. QI requires reapplication every year, and previous QI recipients get priority in the funding queue."
          }
        ],
        "phone": "800-642-3195",
        "sourceUrl": "https://www.michigan.gov/mdhhs/assistance-programs/healthcare/disabilities/dualeligible/medicare-savings-programs",
        "contentStatus": "pipeline-draft",
        "draftedAt": "2026-04-09"
      }
