      {
        "id": "north-dakota-basic-care-assistance-bcap",
        "name": "Basic Care Assistance Program (BCAP)",
        "shortName": "BCAP",
        "tagline": "Helps pay room and board costs if your parent lives in a basic care facility and doesn't qualify for full Medicaid.",
        "programType": "benefit",
        "complexity": "deep",
        "geographicScope": {
          "type": "state",
          "stateVariation": false,
          "localEntities": [
            {
              "name": "Local Human Service Zone offices, county social workers",
              "type": "service-area"
            }
          ]
        },
        "intro": "If your parent lives in a licensed basic care facility in North Dakota and has limited income, BCAP may cover their room and board costs. This program fills a gap for seniors who need assisted living but don't qualify for full Medicaid benefits.\n\nBCAP only works if your parent already lives in (or is moving to) a licensed basic care facility — it won't pay for home care or independent living. Your parent must be 65+ or disabled, be a North Dakota resident, and meet both financial and functional assessment requirements. Because BCAP ties into Medicaid eligibility rules, the application process involves extensive documentation and a personal care assessment.",
        "savingsRange": "",
        "savingsSource": "Room and board payment amount varies by facility and individual assessment",
        "savingsVerified": false,
        "structuredEligibility": {
          "summary": [
            "Age 65+ or disabled/blind 18+",
            "North Dakota resident",
            "Lives in licensed basic care facility",
            "Meets Medicaid-style income limits",
            "Passes functional assessment"
          ],
          "ageRequirement": "65+",
          "incomeTable": null,
          "assetLimits": null,
          "functionalRequirement": "Must complete a Personal Care Services Assessment showing need for assistance with daily activities. Higher care levels (B/C) require Nursing Facility Level of Care assessment.",
          "otherRequirements": [
            "Must live in a licensed Basic Care Facility in North Dakota",
            "Must apply for Medicare if eligible",
            "Must provide Social Security number and extensive documentation"
          ],
          "povertyLevelReference": null
        },
        "applicationGuide": {
          "method": "multiple",
          "summary": "Apply through your local Human Service Zone office using form SFN 405, with processing time not specified.",
          "steps": [
            {
              "step": 1,
              "title": "Contact your local Human Service Zone office",
              "description": "Find your county's office to start the application process and get the required forms."
            },
            {
              "step": 2,
              "title": "Complete Application for Assistance SFN 405",
              "description": "Fill out sections 1, 3, 4, 6, and 8 specifically for BCAP. This covers your parent's basic information, residence, and financial details."
            },
            {
              "step": 3,
              "title": "Gather required documentation",
              "description": "Collect proof of age, identity, residence, financial information, and disability status if applicable."
            },
            {
              "step": 4,
              "title": "Complete Personal Care Services Assessment",
              "description": "A caseworker will assess your parent's functional needs to determine their care level (A, B, or C)."
            },
            {
              "step": 5,
              "title": "Submit application and documents",
              "description": "Turn in completed forms and documentation to your county social worker or Human Service Zone office."
            }
          ],
          "processingTime": null,
          "waitlist": null,
          "tip": "If your parent already receives Medicaid, their financial eligibility will be determined through their Medicaid redetermination process.",
          "urls": [
            {
              "label": "North Dakota Department of Human Services",
              "url": "https://www.nd.gov/dhs/"
            }
          ]
        },
        "contentSections": [
          {
            "type": "documents",
            "heading": "What to Bring",
            "categories": [
              {
                "name": "Identity and Age",
                "items": [
                  "Birth certificate",
                  "Driver's license or state ID",
                  "Social Security number"
                ]
              },
              {
                "name": "Residence",
                "items": [
                  "Rent receipts or lease agreement",
                  "Utility bills",
                  "Documentation showing North Dakota residency"
                ]
              },
              {
                "name": "Financial",
                "items": [
                  "Bank statements",
                  "Social Security award letters",
                  "Pension or retirement income statements",
                  "Any other income documentation"
                ]
              },
              {
                "name": "Medical (if applicable)",
                "items": [
                  "Proof of disability or blindness",
                  "Medicare eligibility documentation"
                ]
              }
            ]
          },
          {
            "type": "callout",
            "tone": "tip",
            "text": "BCAP is specifically for basic care facility residents only. If your parent lives independently or in their own home, this program won't help — look into other North Dakota Medicaid programs instead."
          }
        ],
        "faqs": [
          {
            "question": "What's the difference between BCAP and regular Medicaid?",
            "answer": "BCAP is for people who need some assistance but don't qualify for full Medicaid benefits. It only covers room and board costs in basic care facilities, while Medicaid covers comprehensive medical care and services."
          },
          {
            "question": "Can Mom apply for BCAP if she's already in a basic care facility?",
            "answer": "Yes, she must already be living in a licensed basic care facility to qualify. BCAP won't help her move into a facility — she needs to be a resident first."
          },
          {
            "question": "What if Mom's income is too high for BCAP but she can't afford the facility costs?",
            "answer": "Contact your local Human Service Zone office to explore other options. There may be different Medicaid programs or payment plans available depending on her specific situation."
          },
          {
            "question": "How do they determine what care level Mom needs?",
            "answer": "A caseworker will complete a Personal Care Services Assessment looking at her ability to handle daily activities like bathing, dressing, and medication management. Higher care levels (B and C) require meeting Nursing Facility Level of Care criteria."
          },
          {
            "question": "Can Mom keep her house if she qualifies for BCAP?",
            "answer": "The research doesn't specify BCAP's asset rules, but it follows Medicaid-style eligibility. Contact your local Human Service Zone office for details about how home ownership affects eligibility."
          },
          {
            "question": "What happens if Mom moves to a different basic care facility?",
            "answer": "She'll need to notify her caseworker about the move. BCAP should continue as long as she moves to another licensed basic care facility in North Dakota and still meets all other requirements."
          }
        ],
        "phone": null,
        "sourceUrl": "https://www.nd.gov/dhs/policymanuals/40029/",
        "contentStatus": "pipeline-draft",
        "draftedAt": "2026-04-09"
      }
