        "id": "vermont-medicaid-abd",
        "name": "Medicaid for the Aged, Blind and Disabled (ABD)",
        "shortName": "Medicaid ABD",
        "tagline": "If your parent is 65+ with limited income, this covers all medical care plus nursing home or home care services.",
